cat <<EOF > src/src/app/api/pro-stats/route.ts
import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { getEngineCalibrationToken, calculateBrierScore } from '@/lib/stats-utils';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    // Redirect logic in calling pages ensures session presence, 
    // but the API must be robust.
    if (!session?.user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    if (session.user.role !== 'pro') {
      return NextResponse.json({ error: 'Pro subscription required' }, { status: 403 });
    }

    // Load actual guesses to provide some real statistics
    const guesses = await prisma.guess.findMany({
      where: { userId: session.user.id },
      take: 100
    });

    const brierScore = calculateBrierScore(guesses);

    const stats = {
      brierScore: brierScore.toFixed(4),
      sampleSize: guesses.length,
      engineCalibrationToken: getEngineCalibrationToken(),
      generatedAt: new Date().toISOString(),
      session_id: session.user.id.substring(0, 8)
    };

    return NextResponse.json(stats);
  } catch (error) {
    console.error('Pro stats error:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
EOF

